DECLARE @ActivityId AS BIGINT;

EXEC olaniyi_metadata.usp_start_activity_run
    @BatchId = @BatchId,
    @AssetName = @AssetName,
    @ActivityName = @ActivityName,
    @ActivityType = @ActivityType,
    @ActivityId = @ActivityId OUTPUT

SELECT @ActivityId AS ActivityId

EXEC olaniyi_metadata.usp_end_activity_run
    @ActivityId = @ActivityId,
    @Status = @Status,
    @Metrics = @Metrics,      -- We can add row counts later if needed
    @ErrorMessage = @ErrorMessage

DECLARE @ActivityId  BIGINT;
EXEC olaniyi_metadata.usp_start_activity_run
    @BatchId =     @BatchId,
    @AssetName = @AssetName,
    @ActivityName = @ActivityName,
    @ActivityType =     @ActivityType,
    @ActivityId = @ActivityId  OUTPUT;

SELECT  @ActivityId  AS ActivityId

